import jui from"jui";const langs={zh:{"Login via WeChat QrCode":"微信扫码登录"}},t=e=>jui.u.t(e,langs),post=(e,o)=>jui.u.postJson(e,o),modal=new jui.modal({title:t("Login via WeChat QrCode"),footer:!1,escClose:!0,content:'<div id="login-qrcode"></div><p id="login-msg" style="text-align:center;"></p>',onHidden:()=>{modal.hideLoading()}}),subscribeCookie="g3_wechat_login_hash";document.querySelectorAll("[data-login-element]").forEach(e=>{e.addEventListener("click",e=>{e.preventDefault(),modal.show(),modal.showLoading();document.querySelector("#login-qrcode"),document.querySelector("#login-msg")})});